generated_oml:
// C3: Physical Sensing Components
instance MotorEncoder : DTDFVocab:SensingComponent [
    base:desc "Motor encoder attached to the permanent‑magnet synchronous motor"
    DTDFVocab:producedData MotorEncoderDataTransmitted
]

instance SecondaryEncoder : DTDFVocab:SensingComponent [
    base:desc "Secondary encoder located behind the dual‑gear (gearwheel + cycloidal gearbox) assembly"
    DTDFVocab:producedData SecondaryEncoderDataTransmitted
]

instance CurrentSensor : DTDFVocab:SensingComponent [
    base:desc "Motor current sensor measuring phase current of the permanent‑magnet synchronous motor"
    DTDFVocab:producedData CurrentSensorDataTransmitted
]

instance OutputAngleSensor : DTDFVocab:SensingComponent [
    base:desc "Output angle sensor reading the final joint angle of the first axis"
    DTDFVocab:producedData OutputAngleSensorDataTransmitted
]

// C4: Physical-to-virtual interaction
instance MotorEncoderDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorEncoder
]

instance SecondaryEncoderDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom SecondaryEncoder
]

instance CurrentSensorDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom CurrentSensor
]

instance OutputAngleSensorDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom OutputAngleSensor
]

// C10: Models/Data
instance SysMLEngineeringModel : DTDFVocab:Model [
    base:desc "Structural and behavioral SysML model of the first axis (motor, gearwheel, cycloidal gearbox)"
    DTDFVocab:inputTo SimulinkProcessingEnabler
]

instance SimulinkMotorModel : DTDFVocab:Model [
    base:desc "Simulink model of the permanent‑magnet synchronous motor"
    DTDFVocab:inputTo SimulinkProcessingEnabler
]

instance SimulinkGearboxModel : DTDFVocab:Model [
    base:desc "Simulink model of the dual‑gear gearbox (gearwheel + cycloidal gearbox)"
    DTDFVocab:inputTo SimulinkProcessingEnabler
]

instance FrictionModelCoulombViscous : DTDFVocab:Model [
    base:desc "Coulomb‑Viscous friction model used in the Simulink simulation"
    DTDFVocab:inputTo SimulinkProcessingEnabler
]

instance FrictionModelStribeck : DTDFVocab:Model [
    base:desc "Stribeck friction model used in the Simulink simulation"
    DTDFVocab:inputTo SimulinkProcessingEnabler
]

instance FrictionModelDahl : DTDFVocab:Model [
    base:desc "Dahl friction model used in the Simulink simulation"
    DTDFVocab:inputTo SimulinkProcessingEnabler
]

instance FrictionModelLuGre : DTDFVocab:Model [
    base:desc "LuGre friction model used in the Simulink simulation"
    DTDFVocab:inputTo SimulinkProcessingEnabler
]

// C6: Data instances derived from sensor traces
instance CurrentData : DTDFVocab:Data [
    base:desc "Derived motor current trace computed from CurrentSensorDataTransmitted"
    DTDFVocab:fromData CurrentSensorDataTransmitted
    DTDFVocab:inputTo SimulinkProcessingEnabler
]

instance TorqueData : DTDFVocab:Data [
    base:desc "Derived torque trace computed from motor current and encoder data"
    DTDFVocab:fromData CurrentSensorDataTransmitted
    DTDFVocab:inputTo SimulinkProcessingEnabler
]

instance AngularVelocityData : DTDFVocab:Data [
    base:desc "Derived angular velocity trace computed from encoder data"
    DTDFVocab:fromData MotorEncoderDataTransmitted, SecondaryEncoderDataTransmitted
    DTDFVocab:inputTo SimulinkProcessingEnabler
]

instance PositionData : DTDFVocab:Data [
    base:desc "Position trace of the first axis calculated from encoder data"
    DTDFVocab:fromData MotorEncoderDataTransmitted, SecondaryEncoderDataTransmitted
    DTDFVocab:inputTo SimulinkProcessingEnabler
]

// C11: Enabler
instance SimulinkProcessingEnabler : DTDFVocab:Enabler [
    base:desc "Simulink execution environment orchestrating simulation models and processing sensor traces"
    DTDFVocab:enables RealTimeFrictionIdentificationService, SimulationComparisonService, DashboardVisualizationService, UpdatedFrictionParameterProvisionService
]

// C6: Services
instance RealTimeFrictionIdentificationService : DTDFVocab:Service [
    base:desc "Real‑time friction identification and refinement service running in Simulink"
    DTDFVocab:provides RealTimeFrictionIdentificationInsight
]

instance SimulationComparisonService : DTDFVocab:Service [
    base:desc "Simulation‑based comparison of measured versus simulated kinematics"
    DTDFVocab:provides SimulationComparisonInsight
]

instance DashboardVisualizationService : DTDFVocab:Service [
    base:desc "Dashboard visualization of data traces and model outputs"
    DTDFVocab:provides DashboardVisualizationInsight
]

instance UpdatedFrictionParameterProvisionService : DTDFVocab:Service [
    base:desc "Provision of updated friction parameters to the CNC controller"
    DTDFVocab:provides UpdatedFrictionParametersAction
]

// C17: Insights and Actions
instance RealTimeFrictionIdentificationInsight : DTDFVocab:Insight [
    base:desc "Insight derived from real‑time friction identification for controller tuning"
]

instance SimulationComparisonInsight : DTDFVocab:Insight [
    base:desc "Insight from comparing simulated and measured kinematics for model validation"
]

instance DashboardVisualizationInsight : DTDFVocab:Insight [
    base:desc "Visual insight from dashboard displaying sensor and simulation data"
]

instance UpdatedFrictionParametersAction : DTDFVocab:Action [
    base:desc "Automatic update of the CNC controller with refined friction parameters"
    DTDFVocab:IsAutomatic true
]

// Environment containing components
instance FirstAxisPhysicalEnvironment : DTDFVocab:Environment [
    base:contains MotorEncoder, SecondaryEncoder, CurrentSensor, OutputAngleSensor
]

instance FirstAxisDigitalEnvironment : DTDFVocab:Environment [
    base:contains SimulinkProcessingEnabler, SimulinkMotorModel, SimulinkGearboxModel, FrictionModelCoulombViscous, FrictionModelStribeck, FrictionModelDahl, FrictionModelLuGre, SysMLEngineeringModel, RealTimeFrictionIdentificationService, SimulationComparisonService, DashboardVisualizationService, UpdatedFrictionParameterProvisionService
]

instance virtual_to_physical_interaction : DTDFVocab:VirtualToPhysical [
    base:desc "The digital shadow is passive and does not issue commands back to the physical axis; it only provides processed data and insights for monitoring and control optimization"
]

instance twinning_time_scale : DTDFVocab:TimeScale [
    base:desc "Realtime data streaming with sensor sampling rates captured via MQTT; simulation and calculation models operate at the same resolution as the incoming data, enabling quasi‑instantaneous analysis of friction effects"
]

instance dt_constellation : DTDFVocab:Constellation [
    base:desc "A loosely coupled orchestration comprising the physical asset (robot axis), its AAS, the SysML engineering model, the Simulink simulation models, the data‑calculation and processing components, data‑trace storage, and the visualization dashboard; all components exchange data via MQTT and AAS interfaces"
]

instance life_cycle_stages : DTDFVocab:EvolutionStage [
    base:desc "Operate phase – the digital shadow is built for the operated industrial robot, continuously ingesting live data to improve control accuracy during runtime"
]

instance fidelity_and_validity_considerations : DTDFVocab:FidelityConsideration [
    base:desc "Traceability of every data point back to its source (sensor or simulation) via originates‑from associations; comparison of measured vs. simulated traces to validate friction model accuracy; continuous identification accounting for wear, load, and temperature changes; uncertainty addressed through data‑driven model updates"
]

instance dt_technical_connection : DTDFVocab:TechnicalConnection [
    base:desc "MQTT protocol used to stream high‑frequency sensor data from the robot to the DT; Asset Administration Shells (AAS) provide semantic links between physical assets and digital models; network likely Ethernet‑based for low latency communication"
]
